import{_ as t,o,c as a,a2 as r}from"./chunks/framework.DTa47_fH.js";const m=JSON.parse('{"title":"PowerBI template CHANGELOG","description":"","frontmatter":{},"headers":[],"relativePath":"templates/CHANGELOG.md","filePath":"templates/CHANGELOG.md"}'),s={name:"templates/CHANGELOG.md"};function d(i,e,n,l,c,p){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="powerbi-template-changelog" tabindex="-1">PowerBI template CHANGELOG <a class="header-anchor" href="#powerbi-template-changelog" aria-label="Permalink to &quot;PowerBI template CHANGELOG&quot;">​</a></h1><p>Manual smoke-test log for the SWAO PowerBI templates. One line per smoke test; new entries on top.</p><table tabindex="0"><thead><tr><th>Date</th><th>File</th><th>Version</th><th>Bundle schema</th><th>Smoke result</th></tr></thead><tbody><tr><td>2026-05-24</td><td><code>swao-report.pbit</code> + <code>swao-portfolio.pbit</code></td><td>1.6 (locale-invariant)</td><td>1.2.0</td><td>AUTOMATED PATCH (#0410) -- M-query <code>Csv.Document</code> + <code>Table.TransformColumnTypes</code> now carry <code>Culture=&quot;en-US&quot;</code> so CSV <code>.</code> decimal separator parses correctly on any host locale. Previously a German Windows host rendered <code>Total LLM Cost = 2,197 Mio.</code> for what should be $2.20; same for duration_minutes (<code>448</code> instead of <code>4.48</code>) and coverage_score (<code>99</code> instead of <code>0.99</code>). Patched via <code>scripts/patch-pbit-locale.mjs</code> (sprint-040 round-15): swao-report 18 Csv.Document + 14 TransformColumnTypes; swao-portfolio 19 + 6. v1.5 originals kept as <code>*.v15.bak.pbit</code> for rollback. No visual / measure / page changes; pure M-query culture invariance.</td></tr><tr><td>2026-05-16</td><td><code>swao-portfolio.pbit</code></td><td>1.3</td><td>1.1.0 (20 tables: 18 single-app + fact_app_heatmap + fact_app_summary)</td><td>OK -- operator hand-edit Sprint 030 Day 2 against C:\\swao-e2e portfolio bundle (2 apps: ghostfolio without LLM run, sovereign-health with full assess). All 5 active pages restyled (Waves remains Tier-2 stub for #0068). New patterns: master/detail trio on Compliance + Auditor pages (matrix + Supporting Evidence Tabelle + severity slicer), per-app <code>evidence_url</code> built on <code>link_signal_evidence</code> via Power Query merge with dim_evidence + custom column using <code>EvidenceUrlPrefix &amp; [app_id] &amp; &quot;/&quot; &amp; source_path</code> (resolves #0269 with Option A). RAG palette consistent across all pages. Portfolio Overview adds glossary + RAG gauge. Heatmap shows gap_score with RAG CF + 3 KPI cards (Total Risks / PARTIAL / UNKNOWN) + Control Detail master/detail Tabelle. Risks adds RAG bar chart + 7R donut. Auditor adds 4 KPI cards + RAG table + master/detail trio at bottom. Lessons: portfolio fact_controls.control_id is non-unique across apps so cardinality must be M:M (not M:1) on <code>link_control_signal -&gt; fact_controls</code>; <code>Total GAPs</code> measure returns BLANK without LLM compliance pass so cards must wrap with <code>+0</code> to render as 0. Known: signal_id as 4th matrix row level still triggers InvalidUnconstrainedJoin -- master/detail is the canonical workaround. File size 2.75 MB. Sprint 030 Lane 1 fully closed.</td></tr><tr><td>2026-05-16</td><td><code>swao-report.pbit</code></td><td>1.5</td><td>1.1.0 (Pass 13 Scope Coverage + link_control_signal)</td><td>OK -- operator hand-edit Sprint 030 Day 1+2 against sovereign-health v0.0.38 bundle. Adds #0263 Phase 3 Scope Coverage page (Pass 13 blind-spots) + #0262 hierarchical Compliance / Auditor / Signals master/detail pattern (matrix + evidence Tabelle + severity slicer with RAG CF). Master/detail replaces the single-hierarchy matrix design that hit <code>InvalidUnconstrainedJoin</code> on the M:M bridges (<code>link_control_signal</code> + <code>link_signal_evidence</code>). <code>EvidenceUrlPrefix</code> parameter for SharePoint-vs-local switch; <code>evidence_link</code> Power Query handles the <code>wsp/inputs/</code> source_path inconsistency operator-side (root-cause filed for v1.6 emitter fix). Dashboard page now carries RAG palette (donut by outcome, bar chart by gap count, gauges with target+threshold CF, severity column CF) + SWAO branded header (logo, contacts, doc URL). File size 2.76 MB (vs v1.1 95 KB -- the master/detail + slicer + CF rules + embedded image inflate the .pbit). Sprint 030 Lane 1 swao-report half closed.</td></tr><tr><td>2026-05-12</td><td><code>swao-report.pbit</code></td><td>1.1</td><td>1.1.0 (engagement cols + Pass 11/12 outputs)</td><td>OK -- operator hand-edit fixes #0238 (schemaless Power Query: dropped <code>Columns=N</code>, retyped <code>coverage_score</code> + <code>portability_score</code> from <code>Int64.Type</code> to <code>type number</code>, switched to <code>QuoteStyle.Csv</code>). Now picks up the four engagement metadata columns appended by #0228 (engagement_name, client_code, partnership_lead, engagement_start_date) on <code>dim_app</code>. Coverage tile renders as 50% after Percentage format applied. Compliance + Auditor tabs now populated by Pass 11 + Pass 12 output (#0233 + #0236). Remaining bugs tracked in #0237 (DAX measures: Total Run Duration Min off by 100x; Controls Satisfied returns BLANK instead of 0).</td></tr><tr><td>2026-05-10</td><td><code>swao-report.pbit</code></td><td>1.0</td><td>1.0.0</td><td>OK -- 6 pages render against sovereign-health bundle (21 signals, 7 controls, 6 risks). Includes Latest Assessment freshness card on Dashboard. Known v0.10 fixture limitations: FP Consideration Rate 0% (no FP fields populated); cross-regime heatmap empty (link_control_signal has 0 rows); dim_severity relationship skipped (multi-taxonomy table). Authoring revealed AUTHORING-GUIDE bugs corrected in v1.1 of the guide.</td></tr><tr><td>2026-05-11</td><td><code>swao-portfolio.pbit</code></td><td>1.0</td><td>1.0.0</td><td>OK -- 6 pages render against portfolio bundle (3 apps: ghostfolio/medplum/sovereign-health; 341 signals / 23 controls / 18 risks total). Pages: Portfolio Overview, Heatmap, Compliance, Risks, Waves (Tier-2 stub), Auditor Roll-up. Bundle generated via <code>scripts/portfolio-export-bypass.mjs</code> (Community-tier in-repo authoring; production users on Premium tier use <code>swao export --portfolio</code>). Known limitations: (1) fact_app_heatmap all-zero values -- portfolio aggregator bug, tracked in #0195 + #0196; (2) dim_pass / dim_regime required manual deduplication in Power Query -- aggregator should dedupe by primary key, also #0195; (3) fact_runs contains 1 row (sovereign-health only) -- medplum/ghostfolio are static fixtures without run-manifest; (4) Auditor page Total Signals Gesamt=181 vs bundle fact_signals=341 (~160 rows have app_id not matching dim_app) -- investigate in #0196. Conditional formatting (traffic-light) deferred to v1.1 via #0196.</td></tr></tbody></table><h2 id="how-to-add-an-entry" tabindex="-1">How to add an entry <a class="header-anchor" href="#how-to-add-an-entry" aria-label="Permalink to &quot;How to add an entry&quot;">​</a></h2><p>After saving a template via PowerBI Desktop:</p><ol><li>Note the <code>bundle_schema_version</code> from the <code>manifest.yaml</code> of the bundle you used during authoring.</li><li>Open the saved template in a fresh Desktop session and verify all pages render with non-empty visuals.</li><li>Append a row to the table above with format:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>| 2026-05-09 | swao-report.pbit | 1.0 | 1.0.0 | OK -- 6 pages render against sovereign-health bundle |</span></span></code></pre></div><h2 id="schema-bump-procedure" tabindex="-1">Schema-bump procedure <a class="header-anchor" href="#schema-bump-procedure" aria-label="Permalink to &quot;Schema-bump procedure&quot;">​</a></h2><p>When the star-schema columns change:</p><ul><li><strong>Patch (1.0.0 -&gt; 1.0.1):</strong> additive, optional column. No template change needed; existing template still works. Append a row noting the bundle version.</li><li><strong>Minor (1.0.0 -&gt; 1.1.0):</strong> additive column that the template should display. Update the template (open, refresh, add visual, re-save). Bump template version to 1.1. Append a row.</li><li><strong>Major (1.0.0 -&gt; 2.0.0):</strong> column renamed or removed. Old template will fail to load. Rebuild against the new schema. Bump template version to 2.0. Append a row.</li></ul>',10)])])}const h=t(s,[["render",d]]);export{m as __pageData,h as default};
